async function processBatch(items, container) {
    const batch = container.createTransaction();
    
    for (const item of items) {
        // Simulate processing
        try {
            // Your data processing logic here
            item.processed = true;
            item.processedAt = new Date().toISOString();
            
            batch.upsert(item);
        } catch (error) {
            console.error('Error processing item:', error);
        }
    }
    
    try {
        await batch.execute();
    } catch (error) {
        // Handle batch errors
        console.error('Batch execution error:', error);
        throw error;
    }
}

